DROP DATABASE IF EXISTS leltar_vizsga;
CREATE DATABASE leltar_vizsga CHARACTER SET utf8mb4 COLLATE utf8mb4_hungarian_ci;
USE leltar_vizsga;

-- USERS
CREATE TABLE users (
  id INT NOT NULL AUTO_INCREMENT,
  username VARCHAR(50) NOT NULL UNIQUE,
  password VARCHAR(100) NOT NULL,
  role VARCHAR(20) NOT NULL,
  PRIMARY KEY (id)
) ENGINE=InnoDB;



-- HELYEK
CREATE TABLE leltar_helyek (
  ID_HELY INT NOT NULL AUTO_INCREMENT,
  NEV VARCHAR(100) NOT NULL,
  JELLEG VARCHAR(255) NOT NULL,
  KAPACITAS INT NOT NULL,
  TERULET INT,
  PRIMARY KEY (ID_HELY),
  UNIQUE (NEV)
) ENGINE=InnoDB;



-- KATEGÓRIÁK
CREATE TABLE leltar_kategoriak (
  ID_KATEGORIA INT NOT NULL AUTO_INCREMENT,
  TIPUS VARCHAR(255) NOT NULL,
  KATEGORIA VARCHAR(255) NOT NULL,
  PRIMARY KEY (ID_KATEGORIA),
  UNIQUE (KATEGORIA)
) ENGINE=InnoDB;



CREATE TABLE leltar_tetelek (
  ID_TETEL INT NOT NULL AUTO_INCREMENT,
  NEV VARCHAR(255) NOT NULL,
  ID_KATEGORIA INT NOT NULL,
  ID_HELY INT NOT NULL,
  MENNYISEG INT NOT NULL DEFAULT 1,
  BESZ_AR INT NOT NULL DEFAULT 0,
  BESZ_FORRAS VARCHAR(255) NOT NULL DEFAULT '',
  BESZ_EVE INT,
  LELTSZAM VARCHAR(45),
  GYARTASI_SZAM VARCHAR(45),
  HIBAS ENUM('N','Y') DEFAULT 'N',

  CONSTRAINT pk_tetel PRIMARY KEY (ID_TETEL),
  CONSTRAINT fk_kategoria FOREIGN KEY (ID_KATEGORIA)
      REFERENCES leltar_kategoriak(ID_KATEGORIA),
  CONSTRAINT fk_hely FOREIGN KEY (ID_HELY)
      REFERENCES leltar_helyek(ID_HELY)
) ENGINE=INNODB;

ALTER TABLE leltar_tetelek
ADD KOLCSONZO VARCHAR(50),
ADD KOLCSONZES_DATUMA DATETIME;





CREATE TABLE leltar_fotok (
  ID_FOTO INT NOT NULL AUTO_INCREMENT,
  ID_TETEL INT NOT NULL,
  FILENAME VARCHAR(100) NOT NULL,
  CAPTION VARCHAR(100) NOT NULL DEFAULT '',
  IMG LONGBLOB,
  PRIMARY KEY (ID_FOTO),
  KEY (ID_TETEL),
  CONSTRAINT tetel_foto 
    FOREIGN KEY (ID_TETEL) 
    REFERENCES leltar_tetelek (ID_TETEL)
    ON DELETE CASCADE
) ENGINE=InnoDB;

  
USE `leltar_vizsga`;

ALTER TABLE `leltar_fotok` CHANGE COLUMN `IMG` `IMG` LONGBLOB NULL AFTER `CAPTION`;


CREATE TABLE IF NOT EXISTS `x_fotok` (
  `ID_X` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `TIPUS` int(10) unsigned NOT NULL,
  `FILENAME` varchar(100) NOT NULL,
  PRIMARY KEY (`ID_X`),
  KEY `TIPUS` (`TIPUS`)
) ENGINE=InnoDB AUTO_INCREMENT=58 DEFAULT CHARSET=utf8mb4;




CREATE TABLE IF NOT EXISTS `x_tetelek` (
  `ID_` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `TIPUS` int(10) unsigned NOT NULL,
  `LELTSZAM` varchar(50) NOT NULL DEFAULT '',
  PRIMARY KEY (`ID_`),
  KEY `TIPUS` (`TIPUS`),
  KEY `LELTSZAM` (`LELTSZAM`)
) ENGINE=InnoDB AUTO_INCREMENT=145 DEFAULT CHARSET=utf8mb4;




SELECT 
  xt.ID_ AS ID_TETEL,
  xf.FILENAME
FROM x_tetelek xt
JOIN x_fotok xf ON xt.TIPUS = xf.TIPUS
WHERE xt.ID_ <= (SELECT MAX(ID_TETEL) FROM leltar_tetelek);





